import json

with open('chart.html', 'r') as f:
    content = f.read()

# Find the Vega-Lite spec embedded in the HTML
# It's typically in a script tag
import re
match = re.search(r'var spec = ({.*?});', content, re.DOTALL)
if match:
    spec = json.loads(match.group(1))
    print('Found Vega-Lite spec')
    print('Top-level keys:', list(spec.keys()))
    print('Concat type:', spec.get('concat'))

    # Check for vconcat (top marginal + heatmap) and hconcat (with right marginal)
    if 'vconcat' in spec:
        print('vconcat children:', len(spec['vconcat']))
        for i, child in enumerate(spec['vconcat']):
            print(f'  vconcat[{i}] mark:', child.get('mark'))
            if 'hconcat' in child:
                print(f'  vconcat[{i}] has hconcat with', len(child['hconcat']), 'children')
                for j, hc in enumerate(child['hconcat']):
                    print(f'    hconcat[{j}] mark:', hc.get('mark'))
    elif 'hconcat' in spec:
        print('hconcat children:', len(spec['hconcat']))
        for i, child in enumerate(spec['hconcat']):
            print(f'  hconcat[{i}]:', child.get('mark') or child.get('vconcat', 'vconcat'))
            if 'vconcat' in child:
                print(f'  hconcat[{i}] has vconcat with', len(child['vconcat']), 'children')
                for j, vc in enumerate(child['vconcat']):
                    print(f'    vconcat[{j}] mark:', vc.get('mark'))

    # Check for selection/params
    def find_params(obj, path=''):
        if isinstance(obj, dict):
            if 'params' in obj:
                for p in obj['params']:
                    print(f'  Param at {path}:', json.dumps(p, indent=2)[:200])
            for k, v in obj.items():
                find_params(v, f'{path}.{k}')
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                find_params(v, f'{path}[{i}]')

    print('\\nSelection params:')
    find_params(spec)

    # Check for transform_filter
    def find_filters(obj, path=''):
        if isinstance(obj, dict):
            if 'transform' in obj:
                for t in obj['transform']:
                    if 'filter' in t:
                        print(f'  Filter at {path}:', json.dumps(t)[:150])
            for k, v in obj.items():
                find_filters(v, f'{path}.{k}')
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                find_filters(v, f'{path}[{i}]')

    print('\\nTransform filters:')
    find_filters(spec)
else:
    print('Could not find Vega-Lite spec in HTML')
    # Try alternative pattern
    match2 = re.search(r'spec = ({.*?});', content, re.DOTALL)
    if match2:
        print('Found alternative pattern')
    else:
        print('No spec found at all')
        print('First 500 chars:', content[:500])
"

